// Mengambil data dari input node sebelumnya (Bundle FHIR)
const bundle = items[0].json; 

return [
  {
    json: {
      patient_id: bundle.patientId,
      hr: bundle.entry[0].resource.valueQuantity.value,
      sbp: bundle.entry[1].resource.component[0].valueQuantity.value,
      dbp: bundle.entry[1].resource.component[1].valueQuantity.value,
      spo2: bundle.entry[2].resource.valueQuantity.value,
      temp: bundle.entry[3].resource.valueQuantity.value,
      rr: bundle.entry[4].resource.valueQuantity.value
    }
  }
];

let rawText = $input.first().json.output;

rawText = rawText.replace(/(\d+\.\d{2})\d+/g, '$1');

const cleanedText = rawText.split('\\n').join('\n');

return {
  formatted_output: cleanedText
};

return items.map(item => {
  // Membersihkan semua kunci/key dari spasi tambahan atau karakter aneh
  const row = {};
  for (let key in item.json) {
    row[key.trim()] = item.json[key];
  }

  // Sekarang memanggil "Patient ID" akan jauh lebih aman
  const rawPatientId = $input.first().json.body['Patient ID'];
  const patientRef = "Patient/" + rawPatientId;

  // Helper function untuk membersihkan data angka
  const cleanFloat = (val) => {
    if (val === undefined || val === null || val === '') return 0;
    if (typeof val === 'string') {
      const cleaned = val.replace(/[^0-9.-]/g, '');
      return parseFloat(cleaned) || 0;
    }
    return parseFloat(val) || 0;
  };

  const timestamp = row["Timestamp"] ? row["Timestamp"].replace(" ", "T") : new Date().toISOString();

  return {
    json: {
      patientId: rawPatientId, 
      capturedAt: timestamp,
      resourceType: "Bundle",
      type: "collection",
      entry: [
        {
          resource: {
            resourceType: "Observation",
            status: "final",
            category: [{ coding: [{ system: "http://terminology.hl7.org/CodeSystem/observation-category", code: "vital-signs", display: "Vital Signs" }] }],
            code: { coding: [{ system: "http://loinc.org", code: "8867-4", display: "Heart rate" }] },
            subject: { reference: patientRef },
            effectiveDateTime: timestamp,
            valueQuantity: { value: cleanFloat($input.first().json.body['Heart Rate']), unit: "bpm", system: "http://unitsofmeasure.org", code: "/min" }
          }
        },
        {
          resource: {
            resourceType: "Observation",
            status: "final",
            category: [{ coding: [{ system: "http://terminology.hl7.org/CodeSystem/observation-category", code: "vital-signs" }] }],
            code: { coding: [{ system: "http://loinc.org", code: "85354-9", display: "Blood pressure panel" }] },
            subject: { reference: patientRef },
            effectiveDateTime: timestamp,
            component: [
              {
                code: { coding: [{ system: "http://loinc.org", code: "8480-6", display: "Systolic blood pressure" }] },
                valueQuantity: { value: cleanFloat($input.first().json.body['Systolic Blood Pressure']), unit: "mmHg", system: "http://unitsofmeasure.org", code: "mm[Hg]" }
              },
              {
                code: { coding: [{ system: "http://loinc.org", code: "8462-4", display: "Diastolic blood pressure" }] },
                valueQuantity: { value: cleanFloat($input.first().json.body['Diastolic Blood Pressure']), unit: "mmHg", system: "http://unitsofmeasure.org", code: "mm[Hg]" }
              }
            ]
          }
        },
        {
          resource: {
            resourceType: "Observation",
            status: "final",
            category: [{ coding: [{ system: "http://terminology.hl7.org/CodeSystem/observation-category", code: "vital-signs" }] }],
            code: { coding: [{ system: "http://loinc.org", code: "2708-6", display: "Oxygen saturation" }] },
            subject: { reference: patientRef },
            effectiveDateTime: timestamp,
            valueQuantity: { value: cleanFloat($input.first().json.body['Oxygen Saturation']), unit: "%", system: "http://unitsofmeasure.org", code: "%" }
          }
        },
        {
          resource: {
            resourceType: "Observation",
            status: "final",
            category: [{ coding: [{ system: "http://terminology.hl7.org/CodeSystem/observation-category", code: "vital-signs" }] }],
            code: { coding: [{ system: "http://loinc.org", code: "8310-5", display: "Body temperature" }] },
            subject: { reference: patientRef },
            effectiveDateTime: timestamp,
            valueQuantity: { value: cleanFloat($input.first().json.body['Body Temperature']), unit: "C", system: "http://unitsofmeasure.org", code: "Cel" }
          }
        },
        {
          resource: {
            resourceType: "Observation",
            status: "final",
            category: [{ coding: [{ system: "http://terminology.hl7.org/CodeSystem/observation-category", code: "vital-signs" }] }],
            code: { coding: [{ system: "http://loinc.org", code: "9279-1", display: "Respiratory rate" }] },
            subject: { reference: patientRef },
            effectiveDateTime: timestamp,
            valueQuantity: { value: cleanFloat($input.first().json.body['Respiratory Rate']), unit: "breaths/min", system: "http://unitsofmeasure.org", code: "/min" }
          }
        }
      ]
    }
  };
});
